INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(5,'ENTROPY ','welcomebackpoppunk@gmail.com','https://open.spotify.com/artist/5kLYGzIPGfDvjz4guoQb8Y?si=kxBsNa45TEaWlzwQ2X6WYg','https://www.instagram.com/entropy_punkband?igsh=ZWs1aGRscTJwN21q&utm_source=qr','Pop Punk','We are a four piece band. I don’t know how you guys feel about underage performers but we are in high school. Two of our members live kind of far away so short notice shows aren’t that good for us. Thanks for the consideration.',0,'2026-04-10 05:10:36');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(6,'Rooster Blackspur','booking@roosterblackspur.com','https://Big Dipper” – NMMA SingerSongwriter of the Year (2021): https://open.spotify.com/track/2bgOgZ5KE67y9cYXUE5CIG?si=l74rtYMnRluQXgyOJVzN0g Live Video: https://youtu.be/3O7FJGWtxto?si=Hs2AlGBHM92U6Rk9 Live Solo: https://youtube.com/shorts/EaMJpwehJPA?si=7OtXhxcGFdnrp3eD Latest Video: https://youtu.be/xe_9T01Qvjo?si=1riFLO33RyN8goSWThank you for your time, consideration, and for supporting live music.Attachments areaPreview YouTube video Rooster Blackspur live at Macey Center Performing Arts - 2025 - “Child of the Wild”Preview YouTube video Rooster Blackspur live at Macey Center Performing Arts - 2025 - “Child of the Wild”  Preview YouTube video Rooster Blackspur - “All Hands on Deck”Preview YouTube video Rooster Blackspur - “All Hands on Deck”  Attachments areaPreview YouTube video Rooster Blackspur live at Macey Center Performing Arts - 2025 - “Child of the Wild”Preview YouTube video Rooster Blackspur live at Macey Center Performing Arts - 2025 - “Child of the Wild”  Preview YouTube video Rooster','https://www.roosterblackspur.com','Americana',replace('Greetings,\n\nI’m reaching out to introduce an artist whose presence is as unforgettable as her voice.\nRooster Blackspur is an award-winning singer-songwriter now based in Nashville. Raised in the Alaskan wilderness and shaped by the high deserts of New Mexico, her sound blends folk-roots grit with soulful Americana storytelling — often described as “equal parts Johnny Cash grit and outsider revival preacher.”   \n\nI believe Rooster would be a perfect fit for your venue. Rooster will be passing through on tour and would love to play for you on July 13th if you have an opening.\n\nA seasoned touring artist, Rooster has performed at major festivals and historic venues across the country, including:\nFestivals: Mile of Music (WI) and Red River Rock Folk Festival (NM). \nVenues:  The 5 Spot and Her newest project, The Cinderella Sessions, recorded at Nashville’s historic Cinderella Sound Studio.\nShared Stages:  Ordinary Elephant, Maria Muldaur, and John Craigie.\nMusic & Video: \nOfficial EPK: RoosterBlackspur.com \nBig Dipper” – NMMA SingerSongwriter of the Year (2021): https://open.spotify.com/track/2bgOgZ5KE67y9cYXUE5CIG?si=l74rtYMnRluQXgyOJVzN0g \nLive Video: https://youtu.be/3O7FJGWtxto?si=Hs2AlGBHM92U6Rk9 \nLive Solo: https://youtube.com/shorts/EaMJpwehJPA?si=7OtXhxcGFdnrp3eD \nLatest Video: https://youtu.be/xe_9T01Qvjo?si=1riFLO33RyN8goSW\n\nThank you for your time, consideration, and for supporting live music.\nBest,\nNicole Becker\nBooking Agent\n503-957-3287\nbooking@roosterblackspur.com\n','\n',char(10)),0,'2026-04-19 00:46:59');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(7,'Garrett Buster','garrettbustermusic@gmail.com','https://music.youtube.com/channel/UC6OPTWddaA6OrkMC-_8dPUg','https://instagram.com/garrettbuster','Singer-songwriter driven energetic indie rock with a touch of folk','I''m available for full band shows or solo performances. It''s also worth noting that my singles & EPs on my YouTube Music channel are a far more recent and accurate representation of my music.',0,'2026-04-20 16:46:26');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(8,'Rigacette','rigacette.band@gmail.com','https://SoundCloud.com/rigacette','https://www.instagram.com/rigacette.band/','Trip hop / Downtempo','We would be ready for a show by late May/early June.',0,'2026-04-24 16:41:34');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(9,'Dusrin Tyler Mahealani Hawkins','iheartbeets@yahoo.com','https://www.youtube.com/watch?v=FYORy-fyZbU',NULL,'IBEW Electrician','Came to your venue for the second time last evening.  Dad chaperone for my daughter and all their friends.  I love what you do and want to be of service.  I work full time as an electrician, teach at our training center and would lovingly offer my time and material for the opportunity you''ve created for these kids.  The sound and engineering is superb.  I can help tidy or add circuits.  Hell, a broom even fits our hands.  Please contact me at 816-383-1349 or Vivienne Quijas (my daughter) at 816-383-0640.  Warmest regards.',0,'2026-04-30 01:41:22');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(10,'Amenazar','Mramenazar@yahoo.com','https://amenazar.bandcamp.com/','https://www.facebook.com/AMENAZARBAND/','Alternative','WE bring an intense live performance to every venue.',0,'2026-05-09 04:16:49');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(11,'Hard At Work','hardatwork9009@gmail.com','https://open.spotify.com/artist/788ge6AONjnjHlJQdnDumi?si=HXSOJniXSpa1NfRYh9xrmg','https://www.instagram.com/hardatwork87?igsh=M3lvY3ZxYWNrcW02','Crappy Punk rock/pop punk, ','We would play a mix of Cover songs and some originals, this would be our first gig not in a basment, and we are still looking for a new bassist',0,'2026-05-11 20:45:17');
