INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(14,'whateveramoon','whateveramoon27@gmail.com','https://www.youtube.com/watch?v=lchJbfxEYr8','https://linktr.ee/whateveramoon','Alternative Pop/Rock, our debut album was written, recorded, and produced entirely in our apartment living room on mostly hand-me-down equipment. We are the ultimate everyman.','Our availability is presently quite open. We also play with backing tracks.  ',0,'2026-05-19 16:12:45');
