INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(16,'Sunfish','Carterasears@icloud.com','https://untitled.stream/library/project/pdINVvR2glLIDe3lEtywO','https://www.instagram.com/sunfish.sunfish.sunfish/','Glitch grunge',replace('Hey There!\n\nHope this email finds you well. I’m reaching out on behalf of Sunfish, An alternative rock band from Salt Lake City touring East Coast/Midwest in August\nHelpful Links Here\n\nhttps://sunfishband.com/epk-for-labels\nhttps://open.spotify.com/artist/6pSYsLGxRDhv5iEBzZAI4J?si=t_bbKPNETMmEPZoBGcv-5g\nhttps://www.instagram.com/sunfish.sunfish.sunfish/\n\nWe are hoping to headline with 2 strong locals, on August 10th, please let me know if the date is available. \nLet me know what you think!\n\nCheers, \n \nCarter Sears\nArtist Management\n435-901-0485\nwww.sunfishband.com','\n',char(10)),0,'2026-05-26 21:42:14');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(17,'Doll Exchange','dollexchange1983@gmail.com','https://open.spotify.com/artist/56SZUgNbwHNvit2FRWCGZJ?si=5-I7fgmhTnuXcf1f5-Aq3g','https://linktr.ee/dollexchange?utm_source=linktree_profile_share&ltsid=a029d750-1391-4105-b1d8-2b796fd0a17a','Post Grunge/punk ','Were very flexible with scheduling so keep us in mind for opening if ever needed ',0,'2026-05-28 19:45:49');
INSERT INTO "booking_submissions" ("id","artist_name","email","music_link","social_link","genre","notes","seen","created_at") VALUES(18,'Fan Inquiry','asher.king234@gmail.com','https://hh','https://hh','DIY',replace('Hello, I have been going to shows almost every single day at Howdy and Farewell after work. Could I interview you? I want to learn about your process, history, and maybe start something similar in my country. We could use a local DIY scene everywhere. If you''re at all interested text, call, or email me.\n\nasher.king234@gmail.com\n8167309845','\n',char(10)),0,'2026-06-02 02:01:47');
